import React, { useState, useEffect } from 'react';
import './styles.css';

const App = () => {
   const [nodes, setNodes] = useState([
      { id: 'node1', text: 'Node 1', properties: {} },
      { id: 'node2', text: 'Node 2', properties: {} },
   ]);

   const handleAddNode = () => {
      const newNodeId = `node${nodes.length + 1}`;
      setNodes([...nodes, { id: newNodeId, text: `Node ${nodes.length + 1}`, properties: {} }]);
   };

   return (
      <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
         <div className="relative w-full max-w-md p-4 bg-white rounded-lg shadow">
            <div className="flex items-center justify-between pb-4">
               <h2 className="text-lg font-bold">AI Model Hierarchy Configurator</h2>
               <button className="bg-gray-400 hover:bg-gray-500 text-white font-bold py-2 px-4 rounded" onClick={handleAddNode}>Add Node</button>
            </div>
            <div className="relative w-full h-64 border border-gray-200 rounded-lg overflow-y-scroll">
               {nodes.map((node, index) => (
                  <div key={node.id} className="px-4 py-2 bg-white rounded-lg mb-2">
                     <h3 className="text-lg font-bold">{node.text}</h3>
                     <div className="flex items-center justify-between py-2">
                        <button className="bg-blue-400 hover:bg-blue-500 text-white font-bold py-2 px-4 rounded">Edit</button>
                        <button className="bg-red-400 hover:bg-red-500 text-white font-bold py-2 px-4 rounded">Delete</button>
                     </div>
                  </div>
               ))}
            </div>
         </div>
      </div>
   );
};

export default App;
